export const meta = {
  name: 'coverage-rules-research',
  description: 'Research the most common real-world health-insurance coverage & policy rules across major US insurers, then synthesize a canonical, implementable set',
  phases: [
    { title: 'Research', detail: 'one agent per insurer / topic, web-grounded' },
    { title: 'Synthesize', detail: 'merge into a canonical coverage-rule set + policy shape' },
  ],
}

const RESEARCH_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    provider_or_topic: { type: 'string' },
    policy_level_fields: {
      type: 'array',
      items: { type: 'string' },
      description: 'Fields that live on the plan/policy itself (deductible, OOP max, network tiers, plan year, metal tier, etc.)',
    },
    service_rules: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          service: { type: 'string' },
          cost_share_type: { type: 'string', description: 'copay | coinsurance | full_coverage | mixed' },
          typical_amount: { type: 'string' },
          applies_deductible: { type: 'string', description: 'yes | no | sometimes' },
          limit: { type: 'string', description: 'dollar limit, visit/unit limit, or none' },
          prior_auth: { type: 'string', description: 'required | not required' },
          excluded: { type: 'string', description: 'commonly excluded? yes/no' },
        },
        required: ['service', 'cost_share_type'],
      },
    },
    common_exclusions: { type: 'array', items: { type: 'string' } },
    common_prior_auth_services: { type: 'array', items: { type: 'string' } },
    citations: { type: 'array', items: { type: 'string' } },
  },
  required: ['provider_or_topic', 'service_rules'],
}

const SYNTH_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    policy_structure: {
      type: 'array',
      description: 'The fields a real plan/policy carries — what we should store on Policy',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          field: { type: 'string' },
          plain_english: { type: 'string' },
          keep_for_v1: { type: 'string', description: 'yes | no | maybe — with one-line reason' },
        },
        required: ['field', 'plain_english', 'keep_for_v1'],
      },
    },
    coverage_rules: {
      type: 'array',
      description: 'The 10-15 most common service categories and how each is typically covered',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          service: { type: 'string' },
          plain_english: { type: 'string' },
          cost_share_type: { type: 'string', description: 'copay | coinsurance | full_coverage' },
          typical_value: { type: 'string' },
          applies_deductible: { type: 'boolean' },
          limit_type: { type: 'string', description: 'none | dollar_per_year | visits_per_year' },
          typical_limit: { type: 'string' },
          prior_auth: { type: 'boolean' },
          frequency: { type: 'string', description: 'how universal this benefit is across insurers' },
        },
        required: ['service', 'plain_english', 'cost_share_type', 'applies_deductible', 'limit_type', 'prior_auth'],
      },
    },
    common_exclusions: { type: 'array', items: { type: 'string' } },
    dollar_vs_visit_limits: { type: 'string', description: 'where dollar limits vs visit/unit limits actually show up in practice' },
    modeling_notes: { type: 'array', items: { type: 'string' }, description: 'implications for a typed-config coverage rule model' },
    key_citations: { type: 'array', items: { type: 'string' } },
  },
  required: ['policy_structure', 'coverage_rules', 'common_exclusions', 'dollar_vs_visit_limits', 'modeling_notes'],
}

const TARGETS = [
  { topic: 'UnitedHealthcare standard PPO/HMO plan', hint: 'Find their Summary of Benefits and Coverage (SBC) or member benefits page.' },
  { topic: 'Aetna standard plan', hint: 'Find an Aetna SBC or "what is covered" benefits breakdown.' },
  { topic: 'Cigna standard plan', hint: 'Find a Cigna SBC or benefits summary.' },
  { topic: 'Blue Cross Blue Shield typical plan', hint: 'Find a BCBS plan SBC or benefits grid.' },
  { topic: 'ACA essential health benefits + metal tiers (Bronze/Silver/Gold/Platinum) + HMO/PPO structure', hint: 'healthcare.gov and CMS — the 10 essential health benefits, deductible/OOP-max/actuarial-value structure, in vs out of network.' },
  { topic: 'Common prior-authorization service lists and common plan exclusions across US insurers', hint: 'What services routinely need prior auth (MRI, surgery, specialty drugs) and what is routinely excluded (cosmetic, experimental, etc.).' },
]

phase('Research')
const findings = await parallel(TARGETS.map((t, i) => () =>
  agent(
    `You are researching real US health-insurance coverage rules. Topic: ${t.topic}.\n` +
    `${t.hint}\n\n` +
    `Use WebSearch to find authoritative pages (official insurer SBCs, healthcare.gov, CMS, KFF), then WebFetch the best 1-2 to read details.\n` +
    `Extract the MOST COMMON, REAL patterns — not edge cases:\n` +
    `- What fields live on the plan/policy itself (deductible, out-of-pocket max, network tiers, plan year, metal tier).\n` +
    `- For the common covered services (office visit, specialist, ER, urgent care, preventive/annual physical, imaging/MRI, lab, generic & specialty drugs, physical therapy, mental health, surgery, maternity, etc.): is cost-share a COPAY (flat $) or COINSURANCE (%)? Does the deductible apply first? Is there a DOLLAR limit or a VISIT/UNIT limit per year? Does it need prior authorization?\n` +
    `- Common exclusions and which services routinely require prior auth.\n` +
    `Cite the URLs you used. Prefer concrete numbers (e.g. "$30 PCP copay", "20% coinsurance after deductible", "PT limited to 20 visits/yr").`,
    { label: `research:${t.topic.slice(0, 28)}`, phase: 'Research', agentType: 'general-purpose', schema: RESEARCH_SCHEMA },
  ),
))

const clean = findings.filter(Boolean)
log(`Collected ${clean.length}/${TARGETS.length} research sets`)

phase('Synthesize')
const synthesis = await agent(
  `You are synthesizing research from multiple US health insurers into a canonical, IMPLEMENTABLE coverage-rule set for a claims-processing system that uses TYPED CONFIG (not a DSL), integer cents, and a discriminated cost-share (copay | coinsurance | full_coverage).\n\n` +
  `Raw research (JSON):\n${JSON.stringify(clean, null, 2)}\n\n` +
  `Produce:\n` +
  `1. policy_structure — the fields a real plan/policy carries, each in plain English, with a keep_for_v1 yes/no/maybe + one-line reason. Be ruthless: a take-home v1 should keep only what changes adjudication.\n` +
  `2. coverage_rules — the 10-15 MOST COMMON service categories. For each: plain-English description, cost_share_type (copay|coinsurance|full_coverage), typical_value, applies_deductible (bool), limit_type (none|dollar_per_year|visits_per_year), typical_limit, prior_auth (bool), and how universal it is.\n` +
  `   IMPORTANT realism rules: preventive/annual physical is full_coverage (ACA mandate, no cost-share, no deductible); primary & specialist visits and ER/urgent care are typically COPAY; imaging/MRI, surgery, hospital stays are typically COINSURANCE after deductible; PT/mental-health/chiro commonly carry VISIT limits; durable medical equipment/some therapies carry DOLLAR limits.\n` +
  `3. common_exclusions, common_prior_auth_services.\n` +
  `4. dollar_vs_visit_limits — explain in one paragraph where each kind actually shows up.\n` +
  `5. modeling_notes — implications for a typed-config rule model (e.g. "limit needs a unit type", "copay services waive deductible but count to OOP").\n` +
  `Keep it tight and decision-ready.`,
  { label: 'synthesize', phase: 'Synthesize', agentType: 'general-purpose', schema: SYNTH_SCHEMA },
)

return { synthesis, raw_findings: clean }

