export const meta = {
  name: 'claim-intake-research',
  description: 'Research how real payers structure claim intake/submission and which verifications they run (reject vs deny), across UnitedHealthcare, Cigna, Aetna + industry standards',
  phases: [
    { title: 'Research', detail: 'top-3 payers + claim-standard/verification topic, web-grounded' },
    { title: 'Synthesize', detail: 'canonical claim structure + verification taxonomy + C2 implications' },
  ],
}

const RESEARCH_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    company_or_topic: { type: 'string' },
    how_members_submit: { type: 'string', description: 'channels: online portal, mobile app, mail, provider/EDI; and the reimbursement claim form name if any' },
    claim_envelope_fields: { type: 'array', items: { type: 'string' }, description: 'claim-header/subscriber/patient/provider-level fields' },
    line_item_fields: { type: 'array', items: { type: 'string' }, description: 'per-service fields: procedure code, DOS, charge, units, diagnosis pointer, etc.' },
    validations: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          check: { type: 'string' },
          stage: { type: 'string', description: 'front_end_reject (never adjudicated) | adjudication_deny' },
          note: { type: 'string' },
        },
        required: ['check', 'stage'],
      },
    },
    reject_vs_deny: { type: 'string', description: 'how this source distinguishes a rejected (failed edits) claim from a denied (adjudicated, no) claim' },
    citations: { type: 'array', items: { type: 'string' } },
  },
  required: ['company_or_topic', 'claim_envelope_fields', 'line_item_fields', 'validations'],
}

const SYNTH_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    canonical_envelope_fields: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: { field: { type: 'string' }, plain_english: { type: 'string' }, in_our_v1: { type: 'string', description: 'yes | no | maybe + one-line reason' } },
        required: ['field', 'plain_english', 'in_our_v1'],
      },
    },
    canonical_line_fields: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: { field: { type: 'string' }, plain_english: { type: 'string' }, in_our_v1: { type: 'string' } },
        required: ['field', 'plain_english', 'in_our_v1'],
      },
    },
    verifications: {
      type: 'array',
      description: 'the common claim verifications, each tagged to a stage',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          check: { type: 'string' },
          layer: { type: 'string', description: 'intake_reject | adjudication_deny' },
          plain_english: { type: 'string' },
          in_our_scope: { type: 'string', description: 'yes | no | maybe' },
        },
        required: ['check', 'layer', 'plain_english', 'in_our_scope'],
      },
    },
    how_top3_submit: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: { company: { type: 'string' }, channels: { type: 'string' }, reimbursement_form: { type: 'string' } },
        required: ['company', 'channels'],
      },
    },
    reject_vs_deny: { type: 'string', description: 'the crisp industry distinction between REJECTED and DENIED' },
    implications_for_c2: { type: 'array', items: { type: 'string' }, description: 'what this means for our intake model and the 5 open forks (rejection model, PHI fields, member/policy resolution, sync vs two-phase, duplicate location)' },
    key_citations: { type: 'array', items: { type: 'string' } },
  },
  required: ['canonical_envelope_fields', 'canonical_line_fields', 'verifications', 'reject_vs_deny', 'implications_for_c2'],
}

const TARGETS = [
  { topic: 'UnitedHealthcare member claim submission & reimbursement', hint: 'How a member submits/files a claim (online portal, app, mail), the member reimbursement claim form and its required fields, and what makes a claim get rejected or denied.' },
  { topic: 'Cigna member claim submission & reimbursement', hint: 'Cigna member claim form, how to file, required fields, claim rejection/denial reasons.' },
  { topic: 'Aetna member claim submission & reimbursement', hint: 'Aetna member claim form, how to file, required fields, claim rejection/denial reasons.' },
  { topic: 'Industry-standard claim structure & verifications', hint: 'CMS-1500 / UB-04 / EDI 837P claim fields; clearinghouse front-end edits / claim scrubbing; the difference between a REJECTED claim (failed edits, never adjudicated) and a DENIED claim (adjudicated); common claim edits: member/subscriber match, NPI/provider validity, valid date of service, diagnosis-procedure consistency, duplicate claim detection, required-field/format checks.' },
]

phase('Research')
const findings = await parallel(TARGETS.map((t, i) => () =>
  agent(
    `Research how real US health insurers structure CLAIM INTAKE and which verifications they run. Topic: ${t.topic}.\n` +
    `${t.hint}\n\n` +
    `Use WebSearch to find authoritative pages (official payer member-claim pages and claim forms, CMS, the X12 837 / CMS-1500 standard, clearinghouse "claim rejection vs denial" explainers, AAPC/AHIMA), then WebFetch the best 1-2.\n` +
    `Capture: (a) how a member submits a claim and the reimbursement form's required fields; (b) the claim ENVELOPE/header fields and the per-LINE fields; (c) the VALIDATIONS run, and CRUCIALLY whether each is a front-end REJECT (claim never adjudicated) or an adjudication DENY; (d) the precise reject-vs-deny distinction. Cite URLs.`,
    { label: `research:${t.topic.slice(0, 26)}`, phase: 'Research', agentType: 'general-purpose', schema: RESEARCH_SCHEMA },
  ),
))

const clean = findings.filter(Boolean)
log(`Collected ${clean.length}/${TARGETS.length} research sets`)

phase('Synthesize')
const synthesis = await agent(
  `Synthesize claim-intake research into a decision-ready model for OUR claims system. We have a hard boundary: INTAKE (C2) validates the well-formedness of a submission about a real member → ACCEPTED/REJECTED; ADJUDICATION (C3) decides coverage per line → APPROVED/DENIED. Our claim state machine is SUBMITTED → UNDER_REVIEW → {APPROVED|PARTIALLY_APPROVED|DENIED} → PAID (no REJECTED state yet — that's an open fork). Reimbursement model: plan pays member.\n\n` +
  `Raw research (JSON):\n${JSON.stringify(clean, null, 2)}\n\n` +
  `Produce:\n` +
  `1. canonical_envelope_fields and canonical_line_fields — the real claim structure, each field plain-English, with in_our_v1 (yes/no/maybe + reason). Be ruthless: keep only what a take-home v1 needs; map standard fields (e.g. CMS-1500 boxes, 837 loops) to our simple model.\n` +
  `2. verifications — the common claim checks, each tagged layer = intake_reject (well-formedness/identity, never adjudicated) vs adjudication_deny (coverage), plain-English, in_our_scope.\n` +
  `3. how_top3_submit — UHC/Cigna/Aetna channels + reimbursement form.\n` +
  `4. reject_vs_deny — the crisp distinction, since conflating them is the classic modeling mistake.\n` +
  `5. implications_for_c2 — concrete guidance on our 5 forks: (1) rejection model (400 vs persisted REJECTED state), (2) capture diagnosis_code/provider PHI or not, (3) member/policy existence = intake-reject vs adjudication POLICY_NOT_ACTIVE, (4) synchronous one-pass vs two-phase intake-then-adjudicate, (5) duplicate detection at intake vs adjudication.\n` +
  `Keep it tight and implementable as typed config / simple validators — no DSL, integer cents.`,
  { label: 'synthesize', phase: 'Synthesize', agentType: 'general-purpose', schema: SYNTH_SCHEMA },
)

return { synthesis, raw_findings: clean }
